package com.xwc.open.easybatis.core;import com.xwc.open.easybatis.core.enums.IdType;import lombok.Data;import org.apache.ibatis.session.Configuration;@Datapublic class EasyBatisEnvironment {    private Configuration configuration;    /**     * 如果 tablePrefix 有值就默认开启根据类名映射标明     */    private String tablePrefix;    private IdType idType;    public EasyBatisEnvironment(Configuration configuration) {        this.configuration = configuration;    }    public boolean isUseActualParamName() {        return configuration.isUseActualParamName();    }    public boolean isMapUnderscoreToCamelCase() {        return configuration.isMapUnderscoreToCamelCase();    }    public IdType useGlobalPrimaKeyType() {        return idType;    }}